import React from 'react';
import { MyProvider } from './CreateContext';
import Nav from './Componants/Nav';
import Intro from './Componants/Intro';
import WelcomePage from './Componants/WelcomePage';

function App() {
  return (
    <MyProvider> {/* Wrapping your components with the provider */}
      <div className="App">
        <Nav />
        <Intro />
        <WelcomePage />
      </div>
    </MyProvider>
  );
}

export default App;
